package org.eclipse.rdf4j.sail.memory;

import static org.assertj.core.api.Assertions.assertThat;
import static org.eclipse.rdf4j.model.util.Values.iri;
import static org.eclipse.rdf4j.model.util.Values.literal;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

import org.eclipse.rdf4j.model.base.CoreDatatype;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.junit.jupiter.api.Test;

public class QueryLevelValuesGroupingTest {

	@Test
	public void queryLevelValuesAfterGroupByPreserveUnboundAggregateGroup() {
		String query = String.join("\n",
				"PREFIX : <http://example.com/>",
				"SELECT ?x (COUNT(*) AS ?count) WHERE {",
				"  { ?s :p ?x } UNION { ?s :q ?z }",
				"}",
				"GROUP BY ?x",
				"ORDER BY COALESCE(STR(?x), \"\") COALESCE(STR(?count), \"\")",
				"VALUES (?x ?z) { (1 10) (2 20) }");

		SailRepository repository = new SailRepository(new MemoryStore());
		try {
			repository.init();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.add(iri("http://example.com/a"), iri("http://example.com/p"),
						literal("1", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/b"), iri("http://example.com/p"),
						literal("1", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/c"), iri("http://example.com/p"),
						literal("2", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/d"), iri("http://example.com/q"),
						literal("10", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/e"), iri("http://example.com/q"),
						literal("20", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/f"), iri("http://example.com/q"),
						literal("10", CoreDatatype.XSD.INTEGER));

				String optimizedPlan = connection.prepareTupleQuery(query)
						.explain(Explanation.Level.Optimized)
						.toString();
				List<String> actual = new ArrayList<>();
				try (var result = connection.prepareTupleQuery(query).evaluate()) {
					for (BindingSet bindingSet : QueryResults.asList(result)) {
						actual.add(String.format("x=%s count=%s",
								valueString(bindingSet, "x"),
								valueString(bindingSet, "count")));
					}
				}

				Collections.sort(actual);
				assertThat(actual)
						.as("Optimized plan:%n%s", optimizedPlan)
						.containsExactly(
								"x=1 count=2",
								"x=1 count=3",
								"x=2 count=1",
								"x=2 count=3");
			}
		} finally {
			repository.shutDown();
		}
	}

	@Test
	public void groupByOverUnionWithoutQueryLevelValuesKeepsAllGroups() {
		String query = String.join("\n",
				"PREFIX : <http://example.com/>",
				"SELECT ?x (COUNT(*) AS ?count) WHERE {",
				"  { ?s :p ?x } UNION { ?s :q ?z }",
				"}",
				"GROUP BY ?x",
				"ORDER BY COALESCE(STR(?x), \"\") COALESCE(STR(?count), \"\")");

		SailRepository repository = new SailRepository(new MemoryStore());
		try {
			repository.init();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.add(iri("http://example.com/a"), iri("http://example.com/p"),
						literal("1", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/b"), iri("http://example.com/p"),
						literal("1", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/c"), iri("http://example.com/p"),
						literal("2", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/d"), iri("http://example.com/q"),
						literal("10", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/e"), iri("http://example.com/q"),
						literal("20", CoreDatatype.XSD.INTEGER));
				connection.add(iri("http://example.com/f"), iri("http://example.com/q"),
						literal("10", CoreDatatype.XSD.INTEGER));

				List<String> actual = new ArrayList<>();
				try (var result = connection.prepareTupleQuery(query).evaluate()) {
					for (BindingSet bindingSet : QueryResults.asList(result)) {
						actual.add(String.format("x=%s count=%s",
								valueString(bindingSet, "x"),
								valueString(bindingSet, "count")));
					}
				}

				Collections.sort(actual);
				assertThat(actual).containsExactly(
						"x=1 count=2",
						"x=2 count=1",
						"x=UNBOUND count=3");
			}
		} finally {
			repository.shutDown();
		}
	}

	private String valueString(BindingSet bindingSet, String name) {
		var value = bindingSet.getValue(name);
		return value == null ? "UNBOUND" : value.stringValue();
	}
}
